import { z } from "zod";

const MisconceptionStateSchema = z.enum([
  "entrenched",
  "aware",
  "considering",
  "updating",
  "settled",
]);

export const AuditResultSchema = z.object({
  approve: z.boolean(),
  reason: z.string(),
});

export const GradeResultSchema = z.object({
  scores: z.object({
    framing: z.number().min(1).max(5),
    questions: z.number().min(1).max(5),
    reasoning: z.number().min(1).max(5),
    uncertainty: z.number().min(1).max(5),
    calibration: z.number().min(1).max(5),
  }),
  emoticon: z.enum(["delighted", "happy", "neutral", "concerned", "sad"]),
  tag: z.string().max(40),
  evidence: z.string().max(200),
  state_transition: z
    .object({
      misc_id: z.string(),
      from: MisconceptionStateSchema,
      to: MisconceptionStateSchema,
      reason: z.string(),
    })
    .nullable(),
});

export const SynthResultSchema = z.object({
  moments: z.array(
    z.object({
      turn_index: z.number(),
      type: z.enum(["breakthrough", "missed_opportunity", "pivot", "stumble"]),
      summary: z.string(),
      why_it_mattered: z.string(),
      try_next_time: z.string(),
    }),
  ),
  summary: z.object({
    averages: z.object({
      framing: z.number(),
      questions: z.number(),
      reasoning: z.number(),
      uncertainty: z.number(),
      calibration: z.number(),
    }),
    trend: z.enum(["improving", "flat", "declining"]),
    takeaway: z.string(),
  }),
  ai_literacy: z.object({
    probes_fired: z.number().int().nonnegative(),
    traps_fired: z.number().int().nonnegative(),
    caught: z.number().int().nonnegative(),
    missed: z.number().int().nonnegative(),
    missed_moments: z.array(
      z.object({
        turn_index: z.number(),
        intent: z.enum(["probe_minor", "probe_trap"]),
        summary: z.string(),
      }),
    ),
  }),
});

export const CoachResultSchema = z.object({
  nudge: z.string().min(1).max(400),
  type: z.enum(["stuck", "hint_request", "transfer_check"]),
});

export const PreteachResultSchema = z.object({
  concept_primer: z.string().min(50).max(1500),
  misconception_preview: z.string().min(30).max(800),
  strategy_options: z.array(z.string().max(50)).length(4),
});

export type AuditResult = z.infer<typeof AuditResultSchema>;
export type GradeResult = z.infer<typeof GradeResultSchema>;
export type SynthResult = z.infer<typeof SynthResultSchema>;
export type CoachResult = z.infer<typeof CoachResultSchema>;
export type PreteachResult = z.infer<typeof PreteachResultSchema>;
